import React from "react";
// import style from "../styles/sidebar.module.css";
import HomeSvg from "../Svgs/HomeSvg";
import ManageSvg from "../Svgs/ManageSvg";
const Sidebar = () => {
  return (
    // <div className="row flex-nowrap mt-1" style={{ minHeight: "90vh" }}>
    //   <div className="col-auto col-md-3 col-xl-2 px-sm-2 px-0 bg-light ">
    //     <div className="d-flex flex-column align-items-center align-items-sm-start px-3 pt-2">
    //       <a
    //         href="/"
    //         className="d-flex align-items-center pb-3 mb-md-0 me-md-auto text-white text-decoration-none"
    //       >
    //         <span className="fs-5 d-none d-sm-inline">תפריט</span>
    //       </a>
    //       <ul
    //         className="nav nav-pills flex-column mb-sm-auto mb-0 align-items-center align-items-sm-start"
    //         id="menu"
    //       >
    //         <li className="nav-item ">
    //           <a href="#" className="nav-link align-middle px-0">
    //             <i className="fs-4 ">
    //               <HomeSvg />
    //             </i>{" "}
    //             <span className="ms-1 d-none d-sm-inline">בית</span>
    //           </a>
    //         </li>
    //         <li>
    //           <a
    //             href="#submenu1"
    //             data-bs-toggle="collapse"
    //             className="nav-link px-0 align-middle"
    //           >
    //             <ManageSvg />
    //             <span className="ms-1 d-none d-sm-inline">ניהול</span>{" "}
    //           </a>
    //           <ul
    //             className="collapse show nav flex-column ms-1"
    //             id="submenu1"
    //             data-bs-parent="#menu"
    //           >
    //             <li className="w-100">
    //               <a href="#" className="nav-link px-0">
    //                 {" "}
    //                 <span className="d-none d-sm-inline">Item</span> 1{" "}
    //               </a>
    //             </li>
    //             <li>
    //               <a href="#" className="nav-link px-0">
    //                 {" "}
    //                 <span className="d-none d-sm-inline">Item</span> 2{" "}
    //               </a>
    //             </li>
    //           </ul>
    //         </li>
    //       </ul>
    //       <hr style={{ color: "white" }} />
    //       <div className="dropdown pb-4">
    //         <a
    //           href="#"
    //           className="d-flex align-items-center text-white text-decoration-none dropdown-toggle"
    //           id="dropdownUser1"
    //           data-bs-toggle="dropdown"
    //           aria-expanded="false"
    //         >
    //           <img
    //             src="https://github.com/mdo.png"
    //             alt="hugenerd"
    //             width="30"
    //             height="30"
    //             className="rounded-circle"
    //           />
    //           <span className="d-none d-sm-inline mx-1">loser</span>
    //         </a>
    //         <ul className="dropdown-menu dropdown-menu-dark text-small shadow">
    //           <li>
    //             <a className="dropdown-item" href="#">
    //               New project...
    //             </a>
    //           </li>
    //           <li>
    //             <a className="dropdown-item" href="#">
    //               Settings
    //             </a>
    //           </li>
    //           <li>
    //             <a className="dropdown-item" href="#">
    //               Profile
    //             </a>
    //           </li>
    //           <li>
    //             <hr className="dropdown-divider" />
    //           </li>
    //           <li>
    //             <a className="dropdown-item" href="#">
    //               Sign out
    //             </a>
    //           </li>
    //         </ul>
    //       </div>
    //     </div>
    //   </div>
    //   <div className="col py-3">
    //     <HomeSvg />
    //   </div>
    // </div>
    <>
      <header>
        {/* <!-- Sidebar --> */}
        <nav
          id="sidebarMenu"
          class="collapse d-lg-block sidebar collapse bg-white"
        >
          <div class="position-sticky">
            <div class="list-group list-group-flush mx-3 mt-4">
              <a
                href="#"
                class="list-group-item list-group-item-action py-2 ripple"
                aria-current="true"
              >
                <i class="fas fa-tachometer-alt fa-fw me-3"></i>
                <span>Main dashboard</span>
              </a>
              <a
                href="#"
                class="list-group-item list-group-item-action py-2 ripple active"
              >
                <i class="fas fa-chart-area fa-fw me-3"></i>
                <span>Webiste traffic</span>
              </a>
              <a
                href="#"
                class="list-group-item list-group-item-action py-2 ripple"
              >
                <i class="fas fa-lock fa-fw me-3"></i>
                <span>Password</span>
              </a>
              <a
                href="#"
                class="list-group-item list-group-item-action py-2 ripple"
              >
                <i class="fas fa-chart-line fa-fw me-3"></i>
                <span>Analytics</span>
              </a>
              <a
                href="#"
                class="list-group-item list-group-item-action py-2 ripple"
              >
                <i class="fas fa-chart-pie fa-fw me-3"></i>
                <span>SEO</span>
              </a>
              <a
                href="#"
                class="list-group-item list-group-item-action py-2 ripple"
              >
                <i class="fas fa-chart-bar fa-fw me-3"></i>
                <span>Orders</span>
              </a>
              <a
                href="#"
                class="list-group-item list-group-item-action py-2 ripple"
              >
                <i class="fas fa-globe fa-fw me-3"></i>
                <span>International</span>
              </a>
              <a
                href="#"
                class="list-group-item list-group-item-action py-2 ripple"
              >
                <i class="fas fa-building fa-fw me-3"></i>
                <span>Partners</span>
              </a>
              <a
                href="#"
                class="list-group-item list-group-item-action py-2 ripple"
              >
                <i class="fas fa-calendar fa-fw me-3"></i>
                <span>Calendar</span>
              </a>
              <a
                href="#"
                class="list-group-item list-group-item-action py-2 ripple"
              >
                <i class="fas fa-users fa-fw me-3"></i>
                <span>Users</span>
              </a>
              <a
                href="#"
                class="list-group-item list-group-item-action py-2 ripple"
              >
                <i class="fas fa-money-bill fa-fw me-3"></i>
                <span>Sales</span>
              </a>
            </div>
          </div>
        </nav>
        {/* <!-- Sidebar --> */}

        {/* <!-- Navbar --> */}
        <nav
          id="main-navbar"
          class="navbar navbar-expand-lg navbar-light bg-white fixed-top"
        >
          {/* <!-- Container wrapper --> */}
          <div class="container-fluid">
            {/* <!-- Toggle button --> */}
            <button
              data-mdb-button-init
              class="navbar-toggler"
              type="button"
              data-mdb-collapse-init
              data-mdb-target="#sidebarMenu"
              aria-controls="sidebarMenu"
              aria-expanded="false"
              aria-label="Toggle navigation"
            >
              <i class="fas fa-bars"></i>
            </button>

            {/* <!-- Brand --> */}
            <a class="navbar-brand" href="#">
              <img
                src="https://mdbcdn.b-cdn.net/img/logo/mdb-transaprent-noshadows.webp"
                height="25"
                alt="MDB Logo"
                loading="lazy"
              />
            </a>
            {/* <!-- Search form --> */}
            <form class="d-none d-md-flex input-group w-auto my-auto">
              <input
                autocomplete="off"
                type="search"
                class="form-control rounded"
                placeholder='Search (ctrl + "/" to focus)'
                style="min-width: 225px;"
              />
              <span class="input-group-text border-0">
                <i class="fas fa-search"></i>
              </span>
            </form>

            {/* <!-- Right links --> */}
            <ul class="navbar-nav ms-auto d-flex flex-row">
              {/* <!-- Notification dropdown --> */}
              <li class="nav-item dropdown">
                <a
                  data-mdb-dropdown-init
                  class="nav-link me-3 me-lg-0 dropdown-toggle hidden-arrow"
                  href="#"
                  id="navbarDropdownMenuLink"
                  role="button"
                  data-mdb-toggle="dropdown"
                  aria-expanded="false"
                >
                  <i class="fas fa-bell"></i>
                  <span class="badge rounded-pill badge-notification bg-danger">
                    1
                  </span>
                </a>
                <ul
                  class="dropdown-menu dropdown-menu-end"
                  aria-labelledby="navbarDropdownMenuLink"
                >
                  <li>
                    <a class="dropdown-item" href="#">
                      Some news
                    </a>
                  </li>
                  <li>
                    <a class="dropdown-item" href="#">
                      Another news
                    </a>
                  </li>
                  <li>
                    <a class="dropdown-item" href="#">
                      Something else here
                    </a>
                  </li>
                </ul>
              </li>

              {/* <!-- Icon --> */}
              <li class="nav-item">
                <a class="nav-link me-3 me-lg-0" href="#">
                  <i class="fas fa-fill-drip"></i>
                </a>
              </li>
              {/* <!-- Icon --> */}
              <li class="nav-item me-3 me-lg-0">
                <a class="nav-link" href="#">
                  <i class="fab fa-github"></i>
                </a>
              </li>

              {/* <!-- Icon dropdown --> */}
              <li class="nav-item dropdown">
                <a
                  data-mdb-dropdown-init
                  class="nav-link me-3 me-lg-0 dropdown-toggle hidden-arrow"
                  href="#"
                  id="navbarDropdown"
                  role="button"
                  data-mdb-toggle="dropdown"
                  aria-expanded="false"
                >
                  <i class="flag-united-kingdom flag m-0"></i>
                </a>
                <ul
                  class="dropdown-menu dropdown-menu-end"
                  aria-labelledby="navbarDropdown"
                >
                  <li>
                    <a class="dropdown-item" href="#">
                      <i class="flag-united-kingdom flag"></i>English
                      <i class="fa fa-check text-success ms-2"></i>
                    </a>
                  </li>
                  <li>
                    <hr class="dropdown-divider" />
                  </li>
                  <li>
                    <a class="dropdown-item" href="#">
                      <i class="flag-poland flag"></i>Polski
                    </a>
                  </li>
                  <li>
                    <a class="dropdown-item" href="#">
                      <i class="flag-china flag"></i>中文
                    </a>
                  </li>
                  <li>
                    <a class="dropdown-item" href="#">
                      <i class="flag-japan flag"></i>日本語
                    </a>
                  </li>
                  <li>
                    <a class="dropdown-item" href="#">
                      <i class="flag-germany flag"></i>Deutsch
                    </a>
                  </li>
                  <li>
                    <a class="dropdown-item" href="#">
                      <i class="flag-france flag"></i>Français
                    </a>
                  </li>
                  <li>
                    <a class="dropdown-item" href="#">
                      <i class="flag-spain flag"></i>Español
                    </a>
                  </li>
                  <li>
                    <a class="dropdown-item" href="#">
                      <i class="flag-russia flag"></i>Русский
                    </a>
                  </li>
                  <li>
                    <a class="dropdown-item" href="#">
                      <i class="flag-portugal flag"></i>Português
                    </a>
                  </li>
                </ul>
              </li>

              {/* <!-- Avatar --> */}
              <li class="nav-item dropdown">
                <a
                  data-mdb-dropdown-init
                  class="nav-link dropdown-toggle hidden-arrow d-flex align-items-center"
                  href="#"
                  id="navbarDropdownMenuLink"
                  role="button"
                  data-mdb-toggle="dropdown"
                  aria-expanded="false"
                >
                  <img
                    src="https://mdbcdn.b-cdn.net/img/Photos/Avatars/img (31).webp"
                    class="rounded-circle"
                    height="22"
                    alt="Avatar"
                    loading="lazy"
                  />
                </a>
                <ul
                  class="dropdown-menu dropdown-menu-end"
                  aria-labelledby="navbarDropdownMenuLink"
                >
                  <li>
                    <a class="dropdown-item" href="#">
                      My profile
                    </a>
                  </li>
                  <li>
                    <a class="dropdown-item" href="#">
                      Settings
                    </a>
                  </li>
                  <li>
                    <a class="dropdown-item" href="#">
                      Logout
                    </a>
                  </li>
                </ul>
              </li>
            </ul>
          </div>
          {/* <!-- Container wrapper --> */}
        </nav>
        {/* <!-- Navbar --> */}
      </header>
      {/* <!--Main Navigation--> */}

      {/* <!--Main layout--> */}
      <main style="margin-top: 58px;">
        <div class="container pt-4"></div>
      </main>
      {/* <!--Main layout--> */}
    </>
  );
};

export default Sidebar;
